import { useState, useEffect } from 'react'
import { customersAPI } from '../services/api'
import { useApi, useImageHandling } from '../hooks/useGlobalConfig'
import { toast } from 'react-hot-toast'
import { Plus, Search, Edit2, Trash2, User, Phone, Mail, MapPin, Calendar, Camera, X, Upload } from 'lucide-react'

const Customers = () => {
  const [customers, setCustomers] = useState([])
  const [loading, setLoading] = useState(true)
  const [searchTerm, setSearchTerm] = useState('')
  const [showForm, setShowForm] = useState(false)
  const [editingCustomer, setEditingCustomer] = useState(null)
  const [formData, setFormData] = useState({
    customerId: '',
    name: '',
    fatherName: '',
    dateOfBirth: '',
    address: '',
    pincode: '',
    cellNo: '',
    emailId: '',
    refer: ''
  })
  const [selectedPhoto, setSelectedPhoto] = useState(null)
  const [photoPreview, setPhotoPreview] = useState(null)

  // Use global image handling configuration
  const { getImageUrl, handleImageError } = useImageHandling()

  // Generate automatic customer ID
  const generateCustomerId = () => {
    const now = new Date()
    const year = now.getFullYear()
    const month = String(now.getMonth() + 1).padStart(2, '0')
    const day = String(now.getDate()).padStart(2, '0')
    const random = Math.floor(Math.random() * 1000).toString().padStart(3, '0')
    return `CUST-${year}${month}${day}-${random}`
  }

  useEffect(() => {
    fetchCustomers()
  }, [])

  const fetchCustomers = async () => {
    try {
      setLoading(true)
      const response = await customersAPI.getAll()
      setCustomers(response.data)
    } catch (error) {
      toast.error('Failed to fetch customers')
      console.error('Error fetching customers:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleDelete = async (customerId) => {
    if (window.confirm('Are you sure you want to delete this customer?')) {
      try {
        await customersAPI.delete(customerId)
        toast.success('Customer deleted successfully')
        fetchCustomers()
      } catch (error) {
        toast.error('Failed to delete customer')
        console.error('Error deleting customer:', error)
      }
    }
  }

  const resetForm = () => {
    setFormData({
      customerId: '',
      name: '',
      fatherName: '',
      dateOfBirth: '',
      address: '',
      pincode: '',
      cellNo: '',
      emailId: '',
      refer: ''
    })
    setSelectedPhoto(null)
    setPhotoPreview(null)
    setEditingCustomer(null)
    setShowForm(false)
  }

  const handleEdit = (customer) => {
    setEditingCustomer(customer)
    setFormData({
      customerId: customer.customerId,
      name: customer.name,
      fatherName: customer.fatherName,
      dateOfBirth: customer.dateOfBirth ? new Date(customer.dateOfBirth).toISOString().split('T')[0] : '',
      address: customer.address,
      pincode: customer.pincode,
      cellNo: customer.cellNo,
      emailId: customer.emailId,
      refer: customer.refer || ''
    })
    setSelectedPhoto(null)
    setPhotoPreview(null)
    setShowForm(true)
  }

  const handlePhotoChange = (e) => {
    const file = e.target.files[0]
    if (file) {
      setSelectedPhoto(file)
      const reader = new FileReader()
      reader.onloadend = () => {
        setPhotoPreview(reader.result)
      }
      reader.readAsDataURL(file)
    }
  }

  const handlePhotoUpload = async () => {
    if (!selectedPhoto) {
      toast.error('Please select a photo first')
      return
    }

    const formData = new FormData()
    formData.append('photo', selectedPhoto)

    try {
      let response
      if (editingCustomer) {
        // Update existing customer photo
        response = await customersAPI.updatePhoto(editingCustomer._id, formData)
        toast.success('Photo updated successfully')
      } else {
        // For new customers, we'll upload after creating the customer
        toast.info('Please create the customer first, then upload the photo')
        return
      }
      
      // Update the customer in the local state with the new photo
      if (response.data.photo) {
        setCustomers(prevCustomers => 
          prevCustomers.map(customer => 
            customer._id === editingCustomer._id 
              ? { ...customer, photo: response.data.photo }
              : customer
          )
        )
        
        // Update the editing customer as well
        setEditingCustomer(prev => ({
          ...prev,
          photo: response.data.photo
        }))
      }
      
      setSelectedPhoto(null)
      setPhotoPreview(null)
      fetchCustomers() // Refresh the list
    } catch (error) {
      console.error('Photo upload error:', error)
      const errorMessage = error.response?.data?.message || error.message || 'Failed to upload photo'
      toast.error(errorMessage)
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setLoading(true)

    try {
      let response
      if (editingCustomer) {
        // Update existing customer
        response = await customersAPI.update(editingCustomer._id, formData)
        toast.success('Customer updated successfully')
        
        // If we have a selected photo, upload it after updating
        if (selectedPhoto) {
          await handlePhotoUpload()
        }
      } else {
        // Create new customer
        response = await customersAPI.create(formData)
        toast.success('Customer created successfully')
        
        // If we have a selected photo, upload it after creating
        if (selectedPhoto && response.data._id) {
          const photoFormData = new FormData()
          photoFormData.append('photo', selectedPhoto)
          await customersAPI.uploadPhoto(response.data._id, photoFormData)
          toast.success('Photo uploaded successfully')
        }
      }

      fetchCustomers()
      resetForm()
    } catch (error) {
      console.error('Save customer error:', error)
      const errorMessage = error.response?.data?.message || error.message || 'Failed to save customer'
      toast.error(errorMessage)
    } finally {
      setLoading(false)
    }
  }

  const handlePhotoDelete = async (customerId) => {
    if (window.confirm('Are you sure you want to delete this photo?')) {
      try {
        await customersAPI.deletePhoto(customerId)
        toast.success('Photo deleted successfully')
        fetchCustomers()
      } catch (error) {
        toast.error('Failed to delete photo')
        console.error('Error deleting photo:', error)
      }
    }
  }

  const filteredCustomers = customers.filter(customer =>
    customer.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    customer.customerId.toLowerCase().includes(searchTerm.toLowerCase()) ||
    customer.emailId.toLowerCase().includes(searchTerm.toLowerCase()) ||
    customer.cellNo.includes(searchTerm)
  )

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="p-4 lg:p-6 bg-gray-50 min-h-screen">
      {/* Header */}
      <div className="mb-6 lg:mb-8">
        <h1 className="text-2xl lg:text-3xl font-light text-gray-900">Customer Management</h1>
        <p className="text-gray-600 mt-2 text-sm lg:text-base">Manage your customer database efficiently</p>
      </div>

      {/* Search and Actions */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 lg:gap-6 mb-6 lg:mb-8">
        <div className="lg:col-span-2">
          <div className="card">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-5 w-5" />
              <input
                type="text"
                placeholder="Search customers by name, ID, email, or phone..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="search-input"
              />
            </div>
          </div>
        </div>
        <div>
          <button
            onClick={() => {
              setEditingCustomer(null)
              setFormData({
                ...formData,
                customerId: generateCustomerId()
              })
              setShowForm(true)
            }}
            className="w-full bg-gradient-to-r from-blue-500 to-indigo-600 text-white py-3 px-4 lg:px-6 rounded-lg font-medium hover:from-blue-600 hover:to-indigo-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-all duration-200 shadow-lg hover:shadow-xl transform hover:-translate-y-0.5 flex items-center justify-center space-x-2 text-sm lg:text-base"
          >
            <Plus className="h-4 w-4 lg:h-5 lg:w-5" />
            <span className="hidden sm:inline">Add Customer</span>
            <span className="sm:hidden">Add</span>
          </button>
        </div>
      </div>

      {/* Customer Form Modal */}
      {showForm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg p-4 lg:p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <h2 className="text-xl font-bold mb-4">
              {editingCustomer ? 'Edit Customer' : 'Add New Customer'}
            </h2>
            
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Customer ID *
                  </label>
                  <div className="flex gap-2">
                    <input
                      type="text"
                      required
                      value={formData.customerId}
                      onChange={(e) => setFormData({...formData, customerId: e.target.value})}
                      className="input-field flex-1"
                      disabled={!!editingCustomer}
                      placeholder={editingCustomer ? "" : "Auto-generated (e.g., CUST-20260328-123)"}
                    />
                    {!editingCustomer && (
                      <button
                        type="button"
                        onClick={() => setFormData({...formData, customerId: generateCustomerId()})}
                        className="px-3 py-2 bg-blue-500 text-white text-sm rounded hover:bg-blue-600 transition-colors"
                        title="Generate new Customer ID"
                      >
                        🔄
                      </button>
                    )}
                  </div>
                  {!editingCustomer && (
                    <p className="text-xs text-gray-500 mt-1">Customer ID will be auto-generated if left empty</p>
                  )}
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Name *
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.name}
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                    className="input-field"
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Father Name *
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.fatherName}
                    onChange={(e) => setFormData({...formData, fatherName: e.target.value})}
                    className="input-field"
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Date of Birth *
                  </label>
                  <input
                    type="date"
                    required
                    value={formData.dateOfBirth}
                    onChange={(e) => setFormData({...formData, dateOfBirth: e.target.value})}
                    className="input-field"
                  />
                </div>
                
                <div className="col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Address *
                  </label>
                  <textarea
                    required
                    value={formData.address}
                    onChange={(e) => setFormData({...formData, address: e.target.value})}
                    rows={2}
                    className="input-field"
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Pincode *
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.pincode}
                    onChange={(e) => setFormData({...formData, pincode: e.target.value})}
                    className="input-field"
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Cell Number *
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.cellNo}
                    onChange={(e) => setFormData({...formData, cellNo: e.target.value})}
                    className="input-field"
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Email ID
                  </label>
                  <input
                    type="email"
                    
                    value={formData.emailId}
                    onChange={(e) => setFormData({...formData, emailId: e.target.value})}
                    className="input-field"
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Refer By
                  </label>
                  <select
                    value={formData.refer}
                    onChange={(e) => setFormData({...formData, refer: e.target.value})}
                    className="input-field"
                  >
                    <option value="">Select referral source</option>
                    <option value="Self">Self</option>
                    <option value="VAO's">VAO's</option>
                    <option value="Others">Others</option>
                    <option value="Exist Customer">Exist Customer</option>
                  </select>
                </div>
              </div>
              
              {/* Photo Upload Section */}
              {showForm && (
                <div className="col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Customer Photo
                  </label>
                  <div className="flex items-center space-x-4">
                    <div className="relative">
                      {photoPreview || (editingCustomer && editingCustomer.photo) ? (
                        <div className="relative">
                          <img 
                            src={photoPreview || getImageUrl(editingCustomer?.photo)}
                            alt="Customer" 
                            className="h-24 w-24 rounded-full object-cover border-2 border-gray-200"
                            onError={handleImageError}
                          />
                          {/* Fallback placeholder */}
                          <div 
                            className="h-24 w-24 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300 absolute top-0 left-0"
                            style={{ display: 'none' }}
                          >
                            <User className="h-8 w-8 text-gray-400" />
                          </div>
                          {editingCustomer?.photo && !photoPreview && (
                            <button
                              onClick={() => handlePhotoDelete(editingCustomer._id)}
                              className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 hover:bg-red-600"
                              title="Delete photo"
                            >
                              <X className="h-3 w-3" />
                            </button>
                          )}
                        </div>
                      ) : (
                        <div className="h-24 w-24 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300">
                          <User className="h-8 w-8 text-gray-400" />
                        </div>
                      )}
                    </div>
                    
                    <div className="flex-1">
                      <input
                        type="file"
                        id="photo-upload"
                        accept="image/*"
                        onChange={handlePhotoChange}
                        className="hidden"
                      />
                      <label
                        htmlFor="photo-upload"
                        className="inline-flex items-center px-3 py-2 border border-gray-300 rounded-md shadow-sm text-sm leading-4 font-medium text-gray-700 bg-white hover:bg-gray-50 cursor-pointer"
                      >
                        <Camera className="h-4 w-4 mr-2" />
                        Choose Photo
                      </label>
                      
                      {selectedPhoto && (
                        <button
                          onClick={handlePhotoUpload}
                          className="ml-2 btn-primary"
                          disabled={loading}
                        >
                          <Upload className="h-4 w-4 mr-2" />
                          {editingCustomer ? 'Update Photo' : 'Upload Photo'}
                        </button>
                      )}
                      {!selectedPhoto && (
                        <span className="ml-2 text-sm text-gray-500">
                          Choose a photo to upload
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              )}
              
              <div className="flex justify-end space-x-3 pt-4">
                <button
                  type="button"
                  onClick={resetForm}
                  className="btn-secondary"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="btn-primary"
                >
                  {editingCustomer ? 'Update Customer' : 'Add Customer'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Customers List */}
      <div className="card overflow-hidden p-0">
        {filteredCustomers.length === 0 ? (
          <div className="p-6 lg:p-8 text-center text-gray-500">
            {searchTerm ? 'No customers found matching your search.' : 'No customers found. Add your first customer to get started.'}
          </div>
        ) : (
          <div className="overflow-x-auto bg-white rounded-lg shadow-sm border border-gray-200">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-4 lg:px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    <span className="hidden sm:inline">Photo</span>
                    <span className="sm:hidden">#</span>
                  </th>
                  <th className="px-4 lg:px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider hidden md:table-cell">
                    Customer ID
                  </th>
                  <th className="px-4 lg:px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Name
                  </th>
                  <th className="px-4 lg:px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider hidden lg:table-cell">
                    Father Name
                  </th>
                  <th className="px-4 lg:px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Contact
                  </th>
                  <th className="px-4 lg:px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider hidden xl:table-cell">
                    Address
                  </th>
                  <th className="px-4 lg:px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {filteredCustomers.map((customer) => (
                  <tr key={customer._id} className="hover:bg-gray-50">
                    <td className="px-4 lg:px-6 py-4 whitespace-nowrap">
                      <div className="relative">
                        {customer.photo ? (
                          <>
                            <img 
                              src={getImageUrl(customer.photo)}
                              alt={customer.name}
                              className="h-8 w-8 lg:h-10 lg:w-10 rounded-full object-cover border-2 border-gray-200"
                              onError={handleImageError}
                            />
                            {/* Fallback placeholder */}
                            <div 
                              className="h-8 w-8 lg:h-10 lg:w-10 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300 absolute top-0 left-0"
                              style={{ display: 'none' }}
                            >
                              <User className="h-4 w-4 lg:h-5 lg:w-5 text-gray-400" />
                            </div>
                          </>
                        ) : (
                          <div className="h-8 w-8 lg:h-10 lg:w-10 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300">
                            <User className="h-4 w-4 lg:h-5 lg:w-5 text-gray-400" />
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-4 lg:px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900 hidden md:table-cell">
                      <span className="text-xs lg:text-sm">{customer.customerId}</span>
                    </td>
                    <td className="px-4 lg:px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <User className="h-3 w-3 lg:h-4 lg:w-4 text-gray-400 mr-2" />
                        <div>
                          <div className="text-xs lg:text-sm font-medium text-gray-900">{customer.name}</div>
                          <div className="text-xs text-gray-500 hidden lg:block">
                            {new Date(customer.dateOfBirth).toLocaleDateString()}
                          </div>
                        </div>
                      </div>
                    </td>
                    <td className="px-4 lg:px-6 py-4 whitespace-nowrap text-sm text-gray-900 hidden lg:table-cell">
                      <span className="text-xs lg:text-sm">{customer.fatherName}</span>
                    </td>
                    <td className="px-4 lg:px-6 py-4 whitespace-nowrap">
                      <div className="space-y-1">
                        <div className="flex items-center text-xs lg:text-sm text-gray-900">
                          <Phone className="h-3 w-3 text-gray-400 mr-1" />
                          <span className="hidden sm:inline">{customer.cellNo}</span>
                          <span className="sm:hidden">{customer.cellNo.slice(-4)}</span>
                        </div>
                        <div className="flex items-center text-sm text-gray-900">
                          <Mail className="h-3 w-3 text-gray-400 mr-1" />
                          {customer.emailId}
                        </div>
                      </div>
                    </td>
                    <td className="px-4 lg:px-6 py-4 hidden xl:table-cell">
                      <div className="text-xs lg:text-sm text-gray-900">
                        <div className="flex items-start">
                          <MapPin className="h-3 w-3 text-gray-400 mr-1 mt-0.5" />
                          <div>
                            <div>{customer.address}</div>
                            <div className="text-xs text-gray-500">{customer.pincode}</div>
                          </div>
                        </div>
                      </div>
                      {customer.refer && (
                        <div className="text-xs text-gray-500 mt-1">
                          Referred by: {customer.refer}
                        </div>
                      )}
                    </td>
                    <td className="px-4 lg:px-6 py-4 whitespace-nowrap text-sm font-medium">
                      <div className="flex items-center space-x-1 lg:space-x-2">
                        <button
                          onClick={() => handleEdit(customer)}
                          className="text-blue-600 hover:text-blue-900 p-1 rounded hover:bg-blue-50 transition-colors"
                          title="Edit customer"
                        >
                          <Edit2 className="h-3 w-3 lg:h-4 lg:w-4" />
                        </button>
                        <button
                          onClick={() => handleDelete(customer._id)}
                          className="text-red-600 hover:text-red-900 p-1 rounded hover:bg-red-50 transition-colors"
                          title="Delete customer"
                        >
                          <Trash2 className="h-3 w-3 lg:h-4 lg:w-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  )
}

export default Customers
