import { useState, useEffect } from 'react'
import { API_CONFIG, ERROR_CONFIG, THEME_CONFIG, FORM_CONFIG, AUTH_CONFIG } from '../config/appConfig'

// Custom hook to apply global settings to all pages
export const useGlobalConfig = () => {
  const [config, setConfig] = useState({
    api: API_CONFIG,
    error: ERROR_CONFIG,
    theme: THEME_CONFIG,
    form: FORM_CONFIG,
    auth: AUTH_CONFIG
  })

  // Initialize global settings on mount
  useEffect(() => {
    // Set global error handlers
    window.addEventListener('unhandledrejection', (event) => {
      ERROR_CONFIG.handleApiError(event.reason)
    })

    // Set global API error handlers
    window.addEventListener('error', (event) => {
      if (event.message.includes('API')) {
        ERROR_CONFIG.handleApiError(event.error)
      }
    })

    // Initialize authentication state
    const token = AUTH_CONFIG.getToken()
    if (!token) {
      console.log('No auth token found')
    }

    return () => {
      // Cleanup global listeners
      window.removeEventListener('unhandledrejection', ERROR_CONFIG.handleApiError)
      window.removeEventListener('error', ERROR_CONFIG.handleApiError)
    }
  }, [])

  return config
}

// Hook for API calls with global configuration
export const useApi = () => {
  const config = useGlobalConfig()

  const apiCall = async (endpoint, options = {}) => {
    try {
      const url = `${config.api.BASE_URL}${endpoint}`
      
      const defaultOptions = {
        headers: {
          'Content-Type': 'application/json',
          ...(AUTH_CONFIG.getToken() && { 'Authorization': `Bearer ${AUTH_CONFIG.getToken()}` })
        }
      }

      const response = await fetch(url, { ...defaultOptions, ...options })
      
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`)
      }

      return await response.json()
    } catch (error) {
      ERROR_CONFIG.handleApiError(error)
      throw error
    }
  }

  return { apiCall }
}

// Hook for image handling with global configuration
export const useImageHandling = () => {
  const config = useGlobalConfig()

  const getImageUrl = (photoPath) => {
    return config.api.IMAGE_CONFIG.getImageUrl(photoPath)
  }

  const handleImageError = (e) => {
    e.target.style.display = 'none'
    if (e.target.nextSibling) {
      e.target.nextSibling.style.display = 'flex'
    }
  }

  return { getImageUrl, handleImageError }
}

// Hook for form handling with global configuration
export const useFormHandling = () => {
  const config = useGlobalConfig()

  const validateField = (value, rules) => {
    for (const rule of rules) {
      if (rule.required && !value) {
        return config.form.validation.required
      }
      if (rule.type === 'email' && value) {
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
        if (!emailRegex.test(value)) {
          return config.form.validation.email
        }
      }
      if (rule.type === 'phone' && value) {
        const phoneRegex = /^[0-9]{10}$/
        if (!phoneRegex.test(value)) {
          return config.form.validation.phone
        }
      }
    }
    return null
  }

  const formatDate = (date) => {
    return config.form.formatDate(date)
  }

  const formatCurrency = (amount) => {
    return config.form.formatCurrency(amount)
  }

  return { validateField, formatDate, formatCurrency }
}

export default useGlobalConfig
