import { useState, useEffect } from 'react'
import { Plus, Search, Edit2, Trash2, Package, AlertCircle, FolderOpen, Save, X } from 'lucide-react'

const StockCategories = () => {
  const [categories, setCategories] = useState([])
  const [searchTerm, setSearchTerm] = useState('')
  const [showAddForm, setShowAddForm] = useState(false)
  const [editingCategory, setEditingCategory] = useState(null)
  const [loading, setLoading] = useState(true)

  // Load categories from localStorage on component mount
  useEffect(() => {
    const savedCategories = localStorage.getItem('stockCategories')
    if (savedCategories) {
      try {
        setCategories(JSON.parse(savedCategories))
      } catch (error) {
        console.error('Error parsing saved categories:', error)
        // Set default categories if none exist
        const defaultCategories = [
          { id: 1, name: 'Paper', description: 'Various types of paper for printing', subcategories: 13 },
          { id: 2, name: 'Ink', description: 'Printing inks and toners', subcategories: 13 },
          { id: 3, name: 'Lamination', description: 'Lamination materials and films', subcategories: 11 },
          { id: 4, name: 'Binding', description: 'Binding materials and equipment', subcategories: 11 },
          { id: 5, name: 'Printing Plates', description: 'Printing plates and materials', subcategories: 7 },
          { id: 6, name: 'Chemicals', description: 'Printing chemicals and solutions', subcategories: 9 },
          { id: 7, name: 'Tools', description: 'Printing tools and equipment', subcategories: 9 },
          { id: 8, name: 'Packaging', description: 'Packaging materials and supplies', subcategories: 8 }
        ]
        setCategories(defaultCategories)
        localStorage.setItem('stockCategories', JSON.stringify(defaultCategories))
      }
    } else {
      // Set default categories
      const defaultCategories = [
        { id: 1, name: 'Paper', description: 'Various types of paper for printing', subcategories: 13 },
        { id: 2, name: 'Ink', description: 'Printing inks and toners', subcategories: 13 },
        { id: 3, name: 'Lamination', description: 'Lamination materials and films', subcategories: 11 },
        { id: 4, name: 'Binding', description: 'Binding materials and equipment', subcategories: 11 },
        { id: 5, name: 'Printing Plates', description: 'Printing plates and materials', subcategories: 7 },
        { id: 6, name: 'Chemicals', description: 'Printing chemicals and solutions', subcategories: 9 },
        { id: 7, name: 'Tools', description: 'Printing tools and equipment', subcategories: 9 },
        { id: 8, name: 'Packaging', description: 'Packaging materials and supplies', subcategories: 8 }
      ]
      setCategories(defaultCategories)
      localStorage.setItem('stockCategories', JSON.stringify(defaultCategories))
    }
    setLoading(false)
  }, [])

  // Save categories to localStorage whenever they change
  useEffect(() => {
    if (categories.length > 0) {
      localStorage.setItem('stockCategories', JSON.stringify(categories))
    }
  }, [categories])

  const filteredCategories = categories.filter(category =>
    category.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    category.description.toLowerCase().includes(searchTerm.toLowerCase())
  )

  const handleDelete = (id) => {
    if (window.confirm('Are you sure you want to delete this category?')) {
      const updatedCategories = categories.filter(c => c.id !== id)
      setCategories(updatedCategories)
    }
  }

  const handleEdit = (category) => {
    setEditingCategory(category)
    setShowAddForm(true)
  }

  const handleSave = (e) => {
    e.preventDefault()
    const formData = new FormData(e.target)
    const newCategory = {
      id: editingCategory ? editingCategory.id : Date.now(),
      name: formData.get('name'),
      description: formData.get('description'),
      subcategories: editingCategory ? editingCategory.subcategories : 0
    }

    let updatedCategories
    if (editingCategory) {
      updatedCategories = categories.map(c => c.id === editingCategory.id ? newCategory : c)
    } else {
      updatedCategories = [...categories, newCategory]
    }

    setCategories(updatedCategories)
    setShowAddForm(false)
    setEditingCategory(null)
  }

  const handleClose = () => {
    setShowAddForm(false)
    setEditingCategory(null)
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">Stock Categories Management</h2>
        <button
          onClick={() => setShowAddForm(true)}
          className="flex items-center gap-2 bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 transition-colors text-base font-medium"
        >
          <Plus size={20} />
          Add Category
        </button>
      </div>

      {/* Search */}
      <div className="mb-6">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
          <input
            type="text"
            placeholder="Search categories..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 w-full"
          />
        </div>
      </div>

      {/* Categories List */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Category Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Description</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Subcategories</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredCategories.length === 0 ? (
                <tr>
                  <td colSpan="4" className="px-6 py-4 text-center text-gray-500">
                    No categories found
                  </td>
                </tr>
              ) : (
                filteredCategories.map((category) => (
                  <tr key={category.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <FolderOpen className="text-blue-500 mr-3" size={20} />
                        <div className="text-sm font-medium text-gray-900">{category.name}</div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {category.description}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-blue-100 text-blue-800">
                        {category.subcategories?.length || 0} subcategories
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <button
                        onClick={() => handleEdit(category)}
                        className="text-blue-600 hover:text-blue-900 mr-3 p-2 hover:bg-blue-50 rounded-lg transition-colors"
                        title="Edit Category"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button
                        onClick={() => handleDelete(category.id)}
                        className="text-red-600 hover:text-red-900 p-2 hover:bg-red-50 rounded-lg transition-colors"
                        title="Delete Category"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Category Modal */}
      {showAddForm && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-96 shadow-lg rounded-md bg-white">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-medium text-gray-900">
                {editingCategory ? 'Edit Category' : 'Add New Category'}
              </h3>
              <button
                onClick={handleClose}
                className="text-gray-400 hover:text-gray-500"
              >
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSave} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Category Name</label>
                <input
                  type="text"
                  name="name"
                  defaultValue={editingCategory?.name || ''}
                  required
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                <textarea
                  name="description"
                  rows="3"
                  defaultValue={editingCategory?.description || ''}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div className="flex justify-end space-x-3 pt-4">
                <button
                  type="button"
                  onClick={handleClose}
                  className="px-6 py-3 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 text-base font-medium transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-6 py-3 bg-blue-600 text-white rounded-md hover:bg-blue-700 flex items-center gap-2 text-base font-medium transition-colors"
                >
                  <Save size={18} />
                  {editingCategory ? 'Update' : 'Save'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default StockCategories
