// Global Application Configuration
// This file contains all settings that need to be applied consistently across all pages

// Backend URL Configuration
export const API_CONFIG = {
  // Use render backend for production, local for development
  BASE_URL: window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
    ? 'http://localhost:5001'
    : 'https://two026backend.onrender.com',
  
  // API endpoints
  ENDPOINTS: {
    API: '/api',
    CUSTOMERS: '/api/customers',
    SERVICES: '/api/services',
    SUBSERVICES: '/api/subservices',
    MACHINES: '/api/machines',
    MAINTENANCE: '/api/maintenance',
    DASHBOARD: '/api/dashboard',
    BILLS: '/api/bills',
    EXPENSES: '/api/expenses',
    REMINDERS: '/api/reminders',
    STAFF: '/api/staff'
  }
}

// Image URL Configuration
export const IMAGE_CONFIG = {
  // Get the correct base URL for images
  getImageUrl: (photoPath) => {
    if (!photoPath) return null
    
    // If it's already a full URL, return as is
    if (photoPath.startsWith('http')) {
      return photoPath
    }
    
    // For development, use the backend URL
    // For production, use the production backend URL
    if (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1') {
      return `http://localhost:5001/uploads/${photoPath}`
    } else {
      return `https://two026backend.onrender.com/uploads/${photoPath}`
    }
  }
}

// Error Handling Configuration
export const ERROR_CONFIG = {
  // Global error handling settings
  showToast: (message, type = 'error') => {
    // This will be used by toast notifications
    console.log(`Toast ${type}: ${message}`)
  },
  
  // API error handling
  handleApiError: (error) => {
    console.error('API Error:', error)
    if (error.response?.status === 401) {
      // Redirect to login on auth error
      localStorage.removeItem('authToken')
      localStorage.removeItem('user')
      window.location.href = '/login'
    }
  }
}

// Theme Configuration
export const THEME_CONFIG = {
  // Global theme settings
  colors: {
    primary: 'blue',
    secondary: 'green',
    accent: 'purple',
    warning: 'amber',
    danger: 'red'
  },
  
  // Component styling
  getButtonClasses: (variant = 'primary') => {
    const base = 'px-4 py-2 rounded-lg font-medium transition-colors'
    const variants = {
      primary: 'bg-blue-600 text-white hover:bg-blue-700',
      secondary: 'bg-green-600 text-white hover:bg-green-700',
      danger: 'bg-red-600 text-white hover:bg-red-700',
      outline: 'border border-gray-300 text-gray-700 hover:bg-gray-50'
    }
    return `${base} ${variants[variant] || variants.primary}`
  }
}

// Form Configuration
export const FORM_CONFIG = {
  // Global form settings
  validation: {
    required: 'This field is required',
    email: 'Please enter a valid email',
    phone: 'Please enter a valid phone number'
  },
  
  // Date formatting
  formatDate: (date) => {
    return new Date(date).toLocaleDateString('en-GB')
  },
  
  // Number formatting
  formatCurrency: (amount) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR'
    }).format(amount)
  }
}

// Navigation Configuration
export const NAVIGATION_CONFIG = {
  // Global navigation settings
  routes: [
    { path: '/', name: 'Dashboard', icon: 'BarChart3' },
    { path: '/customers', name: 'Customers', icon: 'Users' },
    { path: '/customer-management', name: 'Customer Management', icon: 'UserPlus' },
    { path: '/machines', name: 'Machines', icon: 'Printer' },
    { path: '/machines-maintenance', name: 'Maintenance', icon: 'Wrench' },
    { path: '/billing', name: 'Billing', icon: 'FileText' },
    { path: '/reports', name: 'Reports', icon: 'PieChart' },
    { path: '/settings', name: 'Settings', icon: 'Settings' }
  ],
  
  // Handle navigation with proper routing
  navigate: (path) => {
    window.history.pushState({}, '', path)
    window.dispatchEvent(new PopStateEvent('popstate'))
  }
}

// Authentication Configuration
export const AUTH_CONFIG = {
  // Global auth settings
  getToken: () => localStorage.getItem('authToken'),
  setToken: (token) => localStorage.setItem('authToken', token),
  removeToken: () => localStorage.removeItem('authToken'),
  
  getUser: () => {
    const user = localStorage.getItem('user')
    return user ? JSON.parse(user) : null
  },
  
  setUser: (user) => localStorage.setItem('user', JSON.stringify(user)),
  removeUser: () => localStorage.removeItem('user')
}

// Export all configurations
export default {
  API: API_CONFIG,
  IMAGE: IMAGE_CONFIG,
  ERROR: ERROR_CONFIG,
  THEME: THEME_CONFIG,
  FORM: FORM_CONFIG,
  NAVIGATION: NAVIGATION_CONFIG,
  AUTH: AUTH_CONFIG
}
