import { useState, useEffect } from 'react'
import { useSearchParams, Link } from 'react-router-dom'
import { 
  Users, 
  Calendar, 
  BarChart3, 
  Settings,
  Plus,
  Bell,
  AlertTriangle,
  Clock
} from 'lucide-react'
import ReminderList from './ReminderList'
import ReminderAdd from './ReminderAdd'
import ReminderReports from './ReminderReports'
import ReminderSettings from './ReminderSettings'

const ReminderManagement = () => {
  const [searchParams] = useSearchParams()
  const [activeTab, setActiveTab] = useState('reminders')

  useEffect(() => {
    const tab = searchParams.get('tab') || 'reminders'
    setActiveTab(tab)
  }, [searchParams])

  const tabs = [
    {
      id: 'reminders',
      name: 'All Reminders',
      icon: Bell,
      component: ReminderList,
      color: 'blue'
    },
    {
      id: 'add-reminder',
      name: 'Add Reminder',
      icon: Plus,
      component: ReminderAdd,
      color: 'green'
    },
    {
      id: 'reports',
      name: 'Reports',
      icon: BarChart3,
      component: ReminderReports,
      color: 'purple'
    },
    {
      id: 'settings',
      name: 'Settings',
      icon: Settings,
      component: ReminderSettings,
      color: 'amber'
    }
  ]

  const ActiveComponent = tabs.find(tab => tab.id === activeTab)?.component || ReminderList

  return (
    <div className="p-4 lg:p-6 bg-gray-50 min-h-screen">
      {/* Tab Navigation */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 mb-8 overflow-hidden">
        <nav className="flex overflow-x-auto overflow-y-hidden">
          {tabs.map((tab) => {
            const Icon = tab.icon
            const isActive = activeTab === tab.id
            const getColorClasses = (color) => {
              switch (color) {
                case 'blue':
                  return isActive 
                    ? 'bg-gradient-to-r from-blue-500 to-blue-600 text-white border-blue-500' 
                    : 'text-gray-600 hover:text-blue-600 hover:bg-blue-50 border-transparent'
                case 'green':
                  return isActive 
                    ? 'bg-gradient-to-r from-green-500 to-green-600 text-white border-green-500' 
                    : 'text-gray-600 hover:text-green-600 hover:bg-green-50 border-transparent'
                case 'purple':
                  return isActive 
                    ? 'bg-gradient-to-r from-purple-500 to-purple-600 text-white border-purple-500' 
                    : 'text-gray-600 hover:text-purple-600 hover:bg-purple-50 border-transparent'
                case 'amber':
                  return isActive 
                    ? 'bg-gradient-to-r from-amber-500 to-amber-600 text-white border-amber-500' 
                    : 'text-gray-600 hover:text-amber-600 hover:bg-amber-50 border-transparent'
                default:
                  return isActive 
                    ? 'bg-gradient-to-r from-gray-500 to-gray-600 text-white border-gray-500' 
                    : 'text-gray-600 hover:text-gray-600 hover:bg-gray-50 border-transparent'
              }
            }
            
            return (
              <Link
                key={tab.id}
                to={`/reminder-management?tab=${tab.id}`}
                className={`flex items-center px-6 py-4 text-sm font-medium border-b-2 transition-all duration-200 whitespace-nowrap ${
                  getColorClasses(tab.color)
                }`}
              >
                <Icon className="h-4 w-4 mr-2" />
                {tab.name}
              </Link>
            )
          })}
        </nav>
      </div>

      {/* Tab Content */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200">
        <ActiveComponent />
      </div>
    </div>
  )
}

export default ReminderManagement
