import { useState, useEffect } from 'react'
import { toast } from 'react-hot-toast'
import { 
  Download, Calendar, TrendingUp, Users, MapPin, Phone, Mail, Filter, 
  FileText, Bell, AlertTriangle, Clock, CheckCircle, BarChart3, PieChart
} from 'lucide-react'
import { customersAPI } from '../../services/api'

const ReminderReports = () => {
  const [reminders, setReminders] = useState([])
  const [loading, setLoading] = useState(true)
  const [reportType, setReportType] = useState('summary')
  const [dateRange, setDateRange] = useState({
    start: '',
    end: ''
  })
  const [statusFilter, setStatusFilter] = useState('all')

  useEffect(() => {
    fetchReminders()
  }, [])

  const fetchReminders = async () => {
    try {
      setLoading(true)
      const response = await customersAPI.getAll()
      const customersWithReminders = response.data.map(customer => ({
        ...customer,
        reminders: customer.reminders || []
      }))
      setReminders(customersWithReminders)
    } catch (error) {
      toast.error('Failed to fetch reminders for reports')
      console.error('Error fetching reminders:', error)
    } finally {
      setLoading(false)
    }
  }

  const getFilteredReminders = () => {
    let filtered = reminders
    
    if (dateRange.start && dateRange.end) {
      filtered = filtered.filter(customer => {
        return (customer.reminders || []).some(reminder => {
          const reminderDate = new Date(reminder.reminderDate)
          const startDate = new Date(dateRange.start)
          const endDate = new Date(dateRange.end)
          return reminderDate >= startDate && reminderDate <= endDate
        })
      })
    }
    
    if (statusFilter !== 'all') {
      filtered = filtered.filter(customer => {
        return (customer.reminders || []).some(reminder => 
          reminder.serviceStatus === statusFilter
        )
      })
    }
    
    return filtered
  }

  const getReportStats = () => {
    const filtered = getFilteredReminders()
    const allReminders = filtered.flatMap(customer => customer.reminders || [])
    
    const stats = {
      total: allReminders.length,
      applied: allReminders.filter(r => r.serviceStatus === 'applied').length,
      pending: allReminders.filter(r => r.serviceStatus === 'pending').length,
      completed: allReminders.filter(r => r.serviceStatus === 'completed').length,
      today: allReminders.filter(r => r.reminderDate === new Date().toISOString().split('T')[0]).length,
      overdue: allReminders.filter(r => new Date(r.reminderDate) < new Date() && r.serviceStatus !== 'completed').length
    }
    
    return stats
  }

  const exportToCSV = () => {
    const filtered = getFilteredReminders()
    const allReminders = filtered.flatMap(customer => 
      (customer.reminders || []).map(reminder => ({
        customerName: customer.name,
        customerId: customer.customerId,
        cellNo: customer.cellNo,
        applicationNo: reminder.applicationNo,
        serviceStatus: reminder.serviceStatus,
        registerDate: reminder.registerDate,
        reminderDate: reminder.reminderDate,
        durationValue: reminder.durationValue,
        durationType: reminder.durationType,
        notes: reminder.notes
      }))
    )

    const headers = ['Customer Name', 'Customer ID', 'Phone', 'Application No', 'Status', 'Register Date', 'Reminder Date', 'Duration', 'Duration Type', 'Notes']
    const csvContent = [
      headers.join(','),
      ...allReminders.map(row => [
        `"${row.customerName}"`,
        `"${row.customerId}"`,
        `"${row.cellNo}"`,
        `"${row.applicationNo}"`,
        `"${row.serviceStatus}"`,
        `"${row.registerDate}"`,
        `"${row.reminderDate}"`,
        `"${row.durationValue}"`,
        `"${row.durationType}"`,
        `"${row.notes}"`
      ].join(','))
    ].join('\n')

    const blob = new Blob([csvContent], { type: 'text/csv' })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `reminder_report_${new Date().toISOString().split('T')[0]}.csv`
    a.click()
    window.URL.revokeObjectURL(url)
    
    toast.success('Report exported successfully')
  }

  const exportToPDF = () => {
    // This would typically use a PDF library like jsPDF
    // For now, we'll simulate it
    toast.info('PDF export feature coming soon')
  }

  const stats = getReportStats()

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="p-6">
      {/* Report Type Selector */}
      <div className="flex flex-wrap gap-4 mb-6">
        <div className="flex items-center space-x-2">
          <label className="text-sm font-medium text-gray-700">Report Type:</label>
          <select
            value={reportType}
            onChange={(e) => setReportType(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          >
            <option value="summary">Summary</option>
            <option value="detailed">Detailed</option>
            <option value="analytics">Analytics</option>
          </select>
        </div>

        <div className="flex items-center space-x-2">
          <label className="text-sm font-medium text-gray-700">Status:</label>
          <select
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          >
            <option value="all">All Status</option>
            <option value="applied">Applied</option>
            <option value="pending">Pending</option>
            <option value="completed">Completed</option>
          </select>
        </div>

        <div className="flex items-center space-x-2">
          <label className="text-sm font-medium text-gray-700">From:</label>
          <input
            type="date"
            value={dateRange.start}
            onChange={(e) => setDateRange({...dateRange, start: e.target.value})}
            className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>

        <div className="flex items-center space-x-2">
          <label className="text-sm font-medium text-gray-700">To:</label>
          <input
            type="date"
            value={dateRange.end}
            onChange={(e) => setDateRange({...dateRange, end: e.target.value})}
            className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>

        <div className="flex items-center space-x-2">
          <button
            onClick={exportToCSV}
            className="px-4 py-2 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors flex items-center"
          >
            <Download className="h-4 w-4 mr-2" />
            Export CSV
          </button>
          <button
            onClick={exportToPDF}
            className="px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors flex items-center"
          >
            <FileText className="h-4 w-4 mr-2" />
            Export PDF
          </button>
        </div>
      </div>

      {reportType === 'summary' && (
        <div className="space-y-6">
          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-6 gap-4">
            <div className="bg-blue-50 p-4 rounded-lg border border-blue-200">
              <div className="text-blue-600 text-sm font-medium">Total Reminders</div>
              <div className="text-2xl font-bold text-blue-900">{stats.total}</div>
            </div>
            <div className="bg-yellow-50 p-4 rounded-lg border border-yellow-200">
              <div className="text-yellow-600 text-sm font-medium">Applied</div>
              <div className="text-2xl font-bold text-yellow-900">{stats.applied}</div>
            </div>
            <div className="bg-orange-50 p-4 rounded-lg border border-orange-200">
              <div className="text-orange-600 text-sm font-medium">Pending</div>
              <div className="text-2xl font-bold text-orange-900">{stats.pending}</div>
            </div>
            <div className="bg-green-50 p-4 rounded-lg border border-green-200">
              <div className="text-green-600 text-sm font-medium">Completed</div>
              <div className="text-2xl font-bold text-green-900">{stats.completed}</div>
            </div>
            <div className="bg-purple-50 p-4 rounded-lg border border-purple-200">
              <div className="text-purple-600 text-sm font-medium">Today</div>
              <div className="text-2xl font-bold text-purple-900">{stats.today}</div>
            </div>
            <div className="bg-red-50 p-4 rounded-lg border border-red-200">
              <div className="text-red-600 text-sm font-medium">Overdue</div>
              <div className="text-2xl font-bold text-red-900">{stats.overdue}</div>
            </div>
          </div>

          {/* Status Distribution Chart */}
          <div className="bg-white p-6 rounded-lg border border-gray-200">
            <h3 className="text-lg font-semibold mb-4 flex items-center">
              <PieChart className="h-5 w-5 mr-2" />
              Status Distribution
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <span className="text-sm font-medium">Applied</span>
                  <div className="flex items-center">
                    <div className="w-32 bg-gray-200 rounded-full h-2 mr-2">
                      <div className="bg-yellow-500 h-2 rounded-full" style={{width: `${stats.total > 0 ? (stats.applied / stats.total) * 100 : 0}%`}}></div>
                    </div>
                    <span className="text-sm text-gray-600">{stats.applied}</span>
                  </div>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-sm font-medium">Pending</span>
                  <div className="flex items-center">
                    <div className="w-32 bg-gray-200 rounded-full h-2 mr-2">
                      <div className="bg-orange-500 h-2 rounded-full" style={{width: `${stats.total > 0 ? (stats.pending / stats.total) * 100 : 0}%`}}></div>
                    </div>
                    <span className="text-sm text-gray-600">{stats.pending}</span>
                  </div>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-sm font-medium">Completed</span>
                  <div className="flex items-center">
                    <div className="w-32 bg-gray-200 rounded-full h-2 mr-2">
                      <div className="bg-green-500 h-2 rounded-full" style={{width: `${stats.total > 0 ? (stats.completed / stats.total) * 100 : 0}%`}}></div>
                    </div>
                    <span className="text-sm text-gray-600">{stats.completed}</span>
                  </div>
                </div>
              </div>
              <div className="text-center">
                <div className="text-3xl font-bold text-gray-900 mb-2">{stats.total}</div>
                <div className="text-sm text-gray-500">Total Reminders</div>
              </div>
            </div>
          </div>
        </div>
      )}

      {reportType === 'detailed' && (
        <div className="bg-white rounded-lg border border-gray-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Customer</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Application No</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Register Date</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Reminder Date</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Duration</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {getFilteredReminders().map((customer) => 
                  (customer.reminders || []).map((reminder, index) => (
                    <tr key={`${customer._id}-${index}`} className="hover:bg-gray-50">
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-sm font-medium text-gray-900">{customer.name}</div>
                        <div className="text-sm text-gray-500">{customer.cellNo}</div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {reminder.applicationNo}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`inline-flex px-2 py-1 text-xs font-medium rounded-full ${
                          reminder.serviceStatus === 'completed' ? 'bg-green-100 text-green-800' :
                          reminder.serviceStatus === 'pending' ? 'bg-orange-100 text-orange-800' :
                          'bg-yellow-100 text-yellow-800'
                        }`}>
                          {reminder.serviceStatus}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {reminder.registerDate}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {reminder.reminderDate}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                        {reminder.durationValue} {reminder.durationType}
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {reportType === 'analytics' && (
        <div className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-lg border border-gray-200">
              <h3 className="text-lg font-semibold mb-4 flex items-center">
                <TrendingUp className="h-5 w-5 mr-2" />
                Completion Rate
              </h3>
              <div className="text-center">
                <div className="text-4xl font-bold text-green-600 mb-2">
                  {stats.total > 0 ? Math.round((stats.completed / stats.total) * 100) : 0}%
                </div>
                <div className="text-sm text-gray-500">
                  {stats.completed} of {stats.total} reminders completed
                </div>
              </div>
            </div>

            <div className="bg-white p-6 rounded-lg border border-gray-200">
              <h3 className="text-lg font-semibold mb-4 flex items-center">
                <AlertTriangle className="h-5 w-5 mr-2" />
                Urgent Attention Required
              </h3>
              <div className="text-center">
                <div className="text-4xl font-bold text-red-600 mb-2">{stats.overdue}</div>
                <div className="text-sm text-gray-500">Overdue reminders</div>
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-lg border border-gray-200">
            <h3 className="text-lg font-semibold mb-4 flex items-center">
              <Calendar className="h-5 w-5 mr-2" />
              Today's Overview
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="text-center p-4 bg-purple-50 rounded-lg">
                <div className="text-2xl font-bold text-purple-900">{stats.today}</div>
                <div className="text-sm text-purple-600">Reminders for today</div>
              </div>
              <div className="text-center p-4 bg-blue-50 rounded-lg">
                <div className="text-2xl font-bold text-blue-900">
                  {stats.today + stats.pending}
                </div>
                <div className="text-sm text-blue-600">Pending actions</div>
              </div>
              <div className="text-center p-4 bg-green-50 rounded-lg">
                <div className="text-2xl font-bold text-green-900">
                  {stats.completed}
                </div>
                <div className="text-sm text-green-600">Completed this week</div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default ReminderReports
