import { useState, useEffect } from 'react'
import { customersAPI } from '../../services/api'
import { toast } from 'react-hot-toast'
import { Download, Calendar, TrendingUp, Users, MapPin, Phone, Mail, Filter, FileText, Camera } from 'lucide-react'

const CustomerReports = () => {
  const [customers, setCustomers] = useState([])
  const [loading, setLoading] = useState(true)
  const [reportType, setReportType] = useState('summary')
  const [dateRange, setDateRange] = useState({
    start: '',
    end: ''
  })

  useEffect(() => {
    fetchCustomers()
  }, [])

  const fetchCustomers = async () => {
    try {
      setLoading(true)
      const response = await customersAPI.getAll()
      setCustomers(response.data)
    } catch (error) {
      toast.error('Failed to fetch customers')
      console.error('Error fetching customers:', error)
    } finally {
      setLoading(false)
    }
  }

  const getFilteredCustomers = () => {
    let filtered = [...customers]
    
    if (dateRange.start && dateRange.end) {
      filtered = filtered.filter(customer => {
        const customerDate = new Date(customer.createdAt)
        return customerDate >= new Date(dateRange.start) && customerDate <= new Date(dateRange.end)
      })
    }
    
    return filtered
  }

  const getStatistics = () => {
    const filtered = getFilteredCustomers()
    const totalCustomers = filtered.length
    
    const customersByRefer = filtered.reduce((acc, customer) => {
      const refer = customer.refer || 'Unknown'
      acc[refer] = (acc[refer] || 0) + 1
      return acc
    }, {})

    const customersByMonth = filtered.reduce((acc, customer) => {
      const date = new Date(customer.createdAt)
      const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`
      acc[monthKey] = (acc[monthKey] || 0) + 1
      return acc
    }, {})

    const customersWithPhotos = filtered.filter(c => c.photo).length
    const customersWithEmail = filtered.filter(c => c.emailId).length

    return {
      totalCustomers,
      customersByRefer,
      customersByMonth,
      customersWithPhotos,
      customersWithEmail,
      photoPercentage: totalCustomers > 0 ? ((customersWithPhotos / totalCustomers) * 100).toFixed(1) : 0,
      emailPercentage: totalCustomers > 0 ? ((customersWithEmail / totalCustomers) * 100).toFixed(1) : 0
    }
  }

  const exportToCSV = (type) => {
    const filtered = getFilteredCustomers()
    
    if (type === 'summary') {
      const stats = getStatistics()
      const headers = ['Metric', 'Value']
      const data = [
        ['Total Customers', stats.totalCustomers],
        ['Customers with Photos', `${stats.customersWithPhotos} (${stats.photoPercentage}%)`],
        ['Customers with Email', `${stats.customersWithEmail} (${stats.emailPercentage}%)`],
        ...Object.entries(stats.customersByRefer).map(([refer, count]) => [`Referred by ${refer}`, count])
      ]
      
      const csvContent = [
        headers.join(','),
        ...data.map(row => row.join(','))
      ].join('\n')

      downloadCSV(csvContent, `customer_summary_${new Date().toISOString().split('T')[0]}.csv`)
    } else if (type === 'detailed') {
      const headers = ['Customer ID', 'Name', 'Father Name', 'Date of Birth', 'Address', 'Pincode', 'Phone', 'Email', 'Refer By', 'Created Date', 'Has Photo']
      const data = filtered.map(customer => [
        customer.customerId,
        customer.name,
        customer.fatherName,
        customer.dateOfBirth,
        `"${customer.address}"`,
        customer.pincode,
        customer.cellNo,
        customer.emailId || '',
        customer.refer || '',
        new Date(customer.createdAt).toLocaleDateString(),
        customer.photo ? 'Yes' : 'No'
      ])
      
      const csvContent = [
        headers.join(','),
        ...data.map(row => row.join(','))
      ].join('\n')

      downloadCSV(csvContent, `customer_detailed_${new Date().toISOString().split('T')[0]}.csv`)
    }
  }

  const downloadCSV = (content, filename) => {
    const blob = new Blob([content], { type: 'text/csv' })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = filename
    a.click()
    window.URL.revokeObjectURL(url)
  }

  const exportToPDF = () => {
    // This would typically use a library like jsPDF
    // For now, we'll create a simple HTML table that can be printed
    const filtered = getFilteredCustomers()
    const stats = getStatistics()
    
    const htmlContent = `
      <html>
        <head>
          <title>Customer Report</title>
          <style>
            body { font-family: Arial, sans-serif; margin: 20px; }
            h1 { color: #333; }
            h2 { color: #666; margin-top: 30px; }
            table { border-collapse: collapse; width: 100%; margin: 20px 0; }
            th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }
            th { background-color: #f2f2f2; }
            .summary-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 20px; margin: 20px 0; }
            .summary-card { border: 1px solid #ddd; padding: 15px; border-radius: 5px; }
            .summary-card h3 { margin: 0 0 10px 0; color: #333; }
            .summary-card .value { font-size: 24px; font-weight: bold; color: #0066cc; }
          </style>
        </head>
        <body>
          <h1>Customer Management Report</h1>
          <p>Generated on: ${new Date().toLocaleDateString()}</p>
          
          <h2>Summary Statistics</h2>
          <div class="summary-grid">
            <div class="summary-card">
              <h3>Total Customers</h3>
              <div class="value">${stats.totalCustomers}</div>
            </div>
            <div class="summary-card">
              <h3>With Photos</h3>
              <div class="value">${stats.customersWithPhotos} (${stats.photoPercentage}%)</div>
            </div>
            <div class="summary-card">
              <h3>With Email</h3>
              <div class="value">${stats.customersWithEmail} (${stats.emailPercentage}%)</div>
            </div>
          </div>
          
          <h2>Referral Sources</h2>
          <table>
            <tr><th>Referral Source</th><th>Count</th><th>Percentage</th></tr>
            ${Object.entries(stats.customersByRefer).map(([refer, count]) => 
              `<tr><td>${refer}</td><td>${count}</td><td>${((count / stats.totalCustomers) * 100).toFixed(1)}%</td></tr>`
            ).join('')}
          </table>
          
          <h2>Customer Details</h2>
          <table>
            <tr>
              <th>Customer ID</th>
              <th>Name</th>
              <th>Phone</th>
              <th>Email</th>
              <th>Address</th>
              <th>Refer By</th>
              <th>Created Date</th>
            </tr>
            ${filtered.map(customer => 
              `<tr>
                <td>${customer.customerId}</td>
                <td>${customer.name}</td>
                <td>${customer.cellNo}</td>
                <td>${customer.emailId || 'N/A'}</td>
                <td>${customer.address}, ${customer.pincode}</td>
                <td>${customer.refer || 'N/A'}</td>
                <td>${new Date(customer.createdAt).toLocaleDateString()}</td>
              </tr>`
            ).join('')}
          </table>
        </body>
      </html>
    `
    
    const blob = new Blob([htmlContent], { type: 'text/html' })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `customer_report_${new Date().toISOString().split('T')[0]}.html`
    a.click()
    window.URL.revokeObjectURL(url)
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  const stats = getStatistics()

  return (
    <div className="space-y-6">
      {/* Report Controls */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Report Type</label>
            <select
              value={reportType}
              onChange={(e) => setReportType(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="summary">Summary Report</option>
              <option value="detailed">Detailed Report</option>
              <option value="analytics">Analytics</option>
            </select>
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Start Date</label>
            <input
              type="date"
              value={dateRange.start}
              onChange={(e) => setDateRange({...dateRange, start: e.target.value})}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
          
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">End Date</label>
            <input
              type="date"
              value={dateRange.end}
              onChange={(e) => setDateRange({...dateRange, end: e.target.value})}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
        </div>
        
        <div className="flex gap-3 mt-4">
          <button
            onClick={() => exportToCSV('summary')}
            className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors flex items-center"
          >
            <Download className="h-4 w-4 mr-2" />
            Export CSV Summary
          </button>
          <button
            onClick={() => exportToCSV('detailed')}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors flex items-center"
          >
            <Download className="h-4 w-4 mr-2" />
            Export CSV Detailed
          </button>
          <button
            onClick={exportToPDF}
            className="px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors flex items-center"
          >
            <FileText className="h-4 w-4 mr-2" />
            Export PDF Report
          </button>
        </div>
      </div>

      {/* Summary Statistics */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="bg-blue-50 p-6 rounded-lg border border-blue-200">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-blue-600 text-sm font-medium">Total Customers</p>
              <p className="text-3xl font-bold text-blue-900">{stats.totalCustomers}</p>
            </div>
            <Users className="h-8 w-8 text-blue-500" />
          </div>
        </div>
        
        <div className="bg-green-50 p-6 rounded-lg border border-green-200">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-green-600 text-sm font-medium">With Photos</p>
              <p className="text-3xl font-bold text-green-900">{stats.customersWithPhotos}</p>
              <p className="text-sm text-green-700">{stats.photoPercentage}%</p>
            </div>
            <Camera className="h-8 w-8 text-green-500" />
          </div>
        </div>
        
        <div className="bg-purple-50 p-6 rounded-lg border border-purple-200">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-purple-600 text-sm font-medium">With Email</p>
              <p className="text-3xl font-bold text-purple-900">{stats.customersWithEmail}</p>
              <p className="text-sm text-purple-700">{stats.emailPercentage}%</p>
            </div>
            <Mail className="h-8 w-8 text-purple-500" />
          </div>
        </div>
        
        <div className="bg-amber-50 p-6 rounded-lg border border-amber-200">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-amber-600 text-sm font-medium">Referral Sources</p>
              <p className="text-3xl font-bold text-amber-900">{Object.keys(stats.customersByRefer).length}</p>
              <p className="text-sm text-amber-700">Total sources</p>
            </div>
            <TrendingUp className="h-8 w-8 text-amber-500" />
          </div>
        </div>
      </div>

      {/* Detailed Content Based on Report Type */}
      {reportType === 'summary' && (
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-semibold mb-4">Referral Analysis</h3>
          <div className="space-y-3">
            {Object.entries(stats.customersByRefer).map(([refer, count]) => (
              <div key={refer} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                <div>
                  <p className="font-medium text-gray-900">{refer}</p>
                  <p className="text-sm text-gray-600">Referral source</p>
                </div>
                <div className="text-right">
                  <p className="text-lg font-semibold text-gray-900">{count}</p>
                  <p className="text-sm text-gray-600">{((count / stats.totalCustomers) * 100).toFixed(1)}%</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {reportType === 'detailed' && (
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-semibold mb-4">Customer List</h3>
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Customer ID</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Name</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Phone</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Email</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Address</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Refer By</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Created</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {getFilteredCustomers().map((customer) => (
                  <tr key={customer._id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      {customer.customerId}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {customer.name}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {customer.cellNo}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {customer.emailId || 'N/A'}
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-900">
                      <div className="flex items-start">
                        <MapPin className="h-3 w-3 text-gray-400 mr-1 mt-0.5" />
                        <div>
                          <div>{customer.address}</div>
                          <div className="text-xs text-gray-500">{customer.pincode}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {customer.refer || 'N/A'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {new Date(customer.createdAt).toLocaleDateString()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {reportType === 'analytics' && (
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-semibold mb-4">Monthly Registration Trends</h3>
          <div className="space-y-3">
            {Object.entries(stats.customersByMonth)
              .sort(([a], [b]) => b.localeCompare(a))
              .slice(0, 12)
              .map(([month, count]) => {
                const [year, monthNum] = month.split('-')
                const monthName = new Date(year, monthNum - 1).toLocaleDateString('en-US', { month: 'long', year: 'numeric' })
                
                return (
                  <div key={month} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div>
                      <p className="font-medium text-gray-900">{monthName}</p>
                      <p className="text-sm text-gray-600">New customers</p>
                    </div>
                    <div className="text-right">
                      <p className="text-lg font-semibold text-gray-900">{count}</p>
                      <div className="w-32 bg-gray-200 rounded-full h-2 mt-1">
                        <div 
                          className="bg-blue-600 h-2 rounded-full"
                          style={{ width: `${(count / Math.max(...Object.values(stats.customersByMonth))) * 100}%` }}
                        ></div>
                      </div>
                    </div>
                  </div>
                )
              })}
          </div>
        </div>
      )}
    </div>
  )
}

export default CustomerReports
